def _cache_salt(self, pred_i: int, demo_set_i: int) -> str:
    # Deterministic given self.rng (seeded upstream) + stable IDs
    if hasattr(self.rng, "getrandbits"):
        base = self.rng.getrandbits(64)
    else:
        base = (pred_i * 2654435761 + demo_set_i * 40503) & 0xFFFFFFFFFFFFFFFF
    n = base ^ ((pred_i & 0xFFFF) << 16) ^ (demo_set_i & 0xFFFF)
    # Base32 (no padding) for compact ASCII salt
    alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567"
    out = []
    x = n
    for _ in range(13):  # 13*5=65 bits coverage
        out.append(alphabet[x & 31]); x >>= 5
    return "".join(out)

def _select_tip_with_weights(self):
    """Select a tip key from TIPS, optionally biased by self.tip_weights.

    Falls back to a uniform draw over TIPS when no weights are configured,
    or when the configured weights are all zero/invalid.
    """
    tip_keys = list(TIPS.keys())

    if not self.tip_weights:
        return self.rng.choice(tip_keys)

    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in tip_keys]
    total_weight = sum(weights)

    if total_weight <= 0:
        return self.rng.choice(tip_keys)

    probabilities = [weight / total_weight for weight in weights]

    threshold = self.rng.random()
    cumulative = 0.0
    for key, probability in zip(tip_keys, probabilities):
        cumulative += probability
        if threshold < cumulative:
            return key

    return tip_keys[-1]

